function solve(points: number[][]): number {
    const n = points.length;
    const slopeMap: Map<string, number[]> = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            let slope: string;

            if (y2 - y1 === 0) {
                slope = "inf"; // horizontal line
            } else if (x2 - x1 === 0) {
                slope = "ver"; // vertical line
            } else {
                slope = (y2 - y1) / (x2 - x1).toString();
            }

            if (!slopeMap.has(slope)) {
                slopeMap.set(slope, []);
            }
            slopeMap.get(slope)!.push(i);
        }
    }

    let count = 0;

    for (const [slope, indices] of slopeMap.entries()) {
        if (indices.length < 2) continue;

        const len = indices.length;
        for (let i = 0; i < len; i++) {
            for (let j = i + 1; j < len; j++) {
                const p1 = indices[i];
                const p2 = indices[j];
                const [x1, y1] = points[p1];
                const [x2, y2] = points[p2];

                const pairs: [number, number][] = [];
                for (let k = 0; k < len; k++) {
                    if (k === i || k === j) continue;
                    const [x3, y3] = points[k];
                    pairs.push([x3, y3]);
                }

                const pairMap: Map<string, number> = new Map();
                for (const [x, y] of pairs) {
                    const key = x + "," + y;
                    pairMap.set(key, (pairMap.get(key) || 0) + 1);
                }

                for (const [key, val] of pairMap.entries()) {
                    if (val >= 2) {
                        count++;
                    }
                }
            }
        }
    }

    return count;
}

